+            let output = run_dcg(&["explain", "--format", "json", cmd]);
+            let stdout = String::from_utf8_lossy(&output.stdout);
+
+            let json: serde_json::Value =
+                serde_json::from_str(&stdout).expect("JSON should be valid");
