+            if json["decision"] == "deny" {
+                let explanation = json["match"]["explanation"].as_str();
+                assert!(
+                    explanation.is_some() && !explanation.unwrap().is_empty(),
+                    "command '{cmd}' JSON should have non-empty explanation\nJSON:\n{stdout}"
+                );
+            }
+        }
+    }
+}

